import{_ as r,o,c as a,a5 as t}from"./chunks/framework.UipYbTJA.js";const v=JSON.parse('{"title":"Provider bootstrap","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/provider-bootstrap.md","filePath":"concepts/provider-bootstrap.md"}'),i={name:"concepts/provider-bootstrap.md"};function d(c,e,n,s,p,l){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="provider-bootstrap" tabindex="-1">Provider bootstrap <a class="header-anchor" href="#provider-bootstrap" aria-label="Permalink to &quot;Provider bootstrap&quot;">​</a></h1><p>Platform Mesh provisions a dedicated kcp workspace for each service provider. Creating a <code>Provider</code> resource triggers that provisioning; the workspace becomes the provider&#39;s domain on the platform, holding their kcp resources (<code>APIExport</code>, <code>APIResourceSchema</code>) and Platform Mesh resources (<code>ContentConfiguration</code>, <code>ProviderMetadata</code>, and RBAC). When provisioning completes, Platform Mesh issues a scoped kubeconfig; the provider is then responsible for bootstrapping everything else.</p><p><code>Provider</code> is the core primitive — any service provider can create one. <code>ManagedProvider</code> is a separate convenience layer for platform admins that builds on top of <code>Provider</code> to automate the full onboarding lifecycle for platform-owned services.</p><h2 id="the-provider-workspace" tabindex="-1">The provider workspace <a class="header-anchor" href="#the-provider-workspace" aria-label="Permalink to &quot;The provider workspace&quot;">​</a></h2><p>Each provider workspace lives under <code>root:providers</code> and is identified by the <code>Provider</code> name combined with the logical cluster ID of the workspace where the <code>Provider</code> object was created. The name is deterministic: two tenants can create a <code>Provider</code> with the same name without colliding, and deleting and recreating a <code>Provider</code> in the same workspace maps back to the same provider workspace.</p><p>The workspace is the provider&#39;s exclusive domain. Platform Mesh creates it and provisions the access credentials inside it — a ServiceAccount, its RBAC binding, and a token, from which the kubeconfig is generated — but manages nothing else there; the provider owns the contents.</p><h2 id="provider" tabindex="-1">Provider <a class="header-anchor" href="#provider" aria-label="Permalink to &quot;Provider&quot;">​</a></h2><p><code>Provider</code> is a kcp-level resource, reconciled by the Provider controller. Creating one provisions a dedicated workspace and a scoped admin kubeconfig for it. It has no effect on the runtime cluster — it operates entirely within kcp.</p><p>Once the workspace is ready, the provider is responsible for:</p><ul><li>Bootstrapping their workspace resources — for example, <code>APIExport</code>, <code>APIResourceSchema</code>, <code>ContentConfiguration</code>, <code>ProviderMetadata</code>, and RBAC.</li><li>Wiring the kubeconfig into their service controllers so those controllers can manage resources in the provider workspace.</li></ul><p>With the workspace bootstrapped, service controllers use the kubeconfig to watch their <code>APIExport</code> virtual workspace and reconcile service consumers.</p><h2 id="managedprovider" tabindex="-1">ManagedProvider <a class="header-anchor" href="#managedprovider" aria-label="Permalink to &quot;ManagedProvider&quot;">​</a></h2><p><code>ManagedProvider</code> is a Platform Mesh runtime resource, reconciled by the Platform Mesh operator. Platform admins use it as a convenience API to onboard platform-owned services: a single resource handles workspace provisioning, kubeconfig distribution, and operator deployment end-to-end.</p><p>On the kcp side, a <code>ManagedProvider</code> creates a <code>Provider</code> and waits for it to be ready — by default named after the <code>ManagedProvider</code> in <code>root:providers:system</code>, or created/adopted at an explicit path via a provider reference. On the runtime side, it copies the resulting kubeconfig into Platform Mesh&#39;s runtime cluster and deploys the service operator components, declared as Helm charts delivered either directly via Flux or resolved from an OCM component.</p><p>The split between <code>Provider</code> and <code>ManagedProvider</code> reflects the split between kcp-level and runtime-level effects: a <code>Provider</code> can only affect kcp, while a <code>ManagedProvider</code> is owned and operated by the platform admin on Platform Mesh&#39;s runtime cluster.</p><p>By default, deleting a <code>ManagedProvider</code> removes the runtime deployments and the copied kubeconfig but leaves the kcp <code>Provider</code> and its workspace intact — giving platform admins room to handle service deprecation, migration, or handoff before committing to full removal. Alternatively, platform admins can opt into full cleanup, which also removes the <code>Provider</code> and cascades to the workspace.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./personas/service-provider.html">Service provider persona</a></li><li><a href="./control-planes.html">Control planes and workspaces</a></li><li><a href="./api-sharing.html">API sharing</a></li><li><a href="./integration-paths.html">Integration paths</a></li><li><a href="/pr-preview/pr-234/reference/components/platform-mesh-operator.html">Platform Mesh operator</a></li><li><a href="/pr-preview/pr-234/reference/resources/provider-resource.html">Provider resource</a></li><li><a href="/pr-preview/pr-234/reference/resources/managed-provider-resource.html">ManagedProvider resource</a></li></ul>',18)])])}const m=r(i,[["render",d]]);export{v as __pageData,m as default};
